import { getAccount, getUserIdFromToken } from '@/api/Account';
import { getUserNotes, createNote } from '@/api/Note';
import { processYouTubeVideo, processDocument, processAudio } from '@/api/AI';
import Sidebar from '@/components/Sidebar.vue';
import { useNotification } from '@/composables/useNotification';
export default {
  name: 'Dashboard',
  components: {
    Sidebar
  },
  setup() {
    const {
      showSuccess,
      showError,
      showInfo,
      showWarning
    } = useNotification();
    return {
      showSuccess,
      showError,
      showInfo,
      showWarning
    };
  },
  data() {
    return {
      userName: 'Loading...',
      userEmail: '',
      userId: null,
      recentNotes: [],
      loading: true,
      error: null,
      // Modal states
      showAudioModal: false,
      showYouTubeModal: false,
      showDocumentModal: false,
      showProcessingModal: false,
      // Audio recording
      isRecording: false,
      mediaRecorder: null,
      audioBlob: null,
      recordingTime: 0,
      recordingTimer: null,
      selectedAudioFile: null,
      isDragOver: false,
      // YouTube
      youtubeUrl: '',
      // Document upload
      selectedDocumentFile: null,
      isDragOverDoc: false,
      // Processing
      processingMessage: '',
      processingProgress: 0,
      isProcessing: false
    };
  },
  async mounted() {
    await this.loadUserData();
    this.loadRecentNotes();
  },
  methods: {
    getParticleSize(index) {
      const sizes = ['small', 'medium', 'large'];
      return sizes[index % 3];
    },
    getParticleColor(index) {
      const colors = ['blue', 'purple', 'pink', 'cyan'];
      return colors[index % 4];
    },
    async loadUserData() {
      try {
        this.loading = true;
        this.error = null;

        // Get user ID from JWT token (synchronous call)
        const userId = this.getUserIdFromToken();
        if (!userId) {
          throw new Error('No valid user token found');
        }
        this.userId = userId;

        // Fetch user account data
        const accountData = await getAccount(userId);
        this.userName = accountData.username;
        this.userEmail = accountData.email;
        this.userLevel = accountData.currentLevel;

        // Fetch recent notes
        try {
          const notesResponse = await getUserNotes(userId);
          // Handle API response structure - extract data array
          const notesData = notesResponse.data || notesResponse || [];

          // Ensure notesData is an array before calling slice
          if (Array.isArray(notesData)) {
            this.recentNotes = notesData.slice(0, 6).map(note => ({
              id: note._id,
              title: note.title,
              content: note.content,
              category: note.category,
              isFavorite: note.isFavorite,
              updatedAt: note.date_updated || note.updatedAt
            }));
          } else {
            console.warn('Notes data is not an array:', notesData);
            this.recentNotes = [];
          }
        } catch (notesError) {
          console.error('Error loading notes:', notesError);
          this.showWarning('Could not load recent notes');
          this.recentNotes = [];
        }
      } catch (error) {
        console.error('Error loading user data:', error);
        this.error = 'Failed to load user data';
        this.showError('Failed to load user data');

        // If token is invalid, redirect to login
        if (error.message.includes('token') || error.response?.status === 401) {
          localStorage.removeItem('token');
          this.$router.push('/login');
        }
      } finally {
        this.loading = false;
      }
    },
    getUserIdFromToken() {
      try {
        const token = localStorage.getItem('token');
        if (!token) return null;
        // Decode JWT token (simple base64 decode for payload)
        const payload = JSON.parse(atob(token.split('.')[1]));
        return payload.id;
      } catch (error) {
        console.error('Error decoding token:', error);
        this.showError('Error', 'Error decoding authentication token');
        return null;
      }
    },
    logout() {
      // Clear authentication token
      localStorage.removeItem('token');
      // Redirect to login
      this.$router.push('/login');
    },
    // Modal methods
    openAudioModal() {
      this.showAudioModal = true;
      this.resetAudioState();
    },
    closeAudioModal() {
      this.showAudioModal = false;
      this.stopRecording();
      this.resetAudioState();
    },
    openYouTubeModal() {
      this.showYouTubeModal = true;
      this.youtubeUrl = '';
    },
    closeYouTubeModal() {
      this.showYouTubeModal = false;
      this.youtubeUrl = '';
    },
    openDocumentModal() {
      this.showDocumentModal = true;
      this.selectedDocumentFile = null;
    },
    closeDocumentModal() {
      this.showDocumentModal = false;
      this.selectedDocumentFile = null;
    },
    // Audio recording methods
    async startRecording() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({
          audio: true
        });
        this.mediaRecorder = new MediaRecorder(stream);
        const audioChunks = [];
        this.mediaRecorder.ondataavailable = event => {
          audioChunks.push(event.data);
        };
        this.mediaRecorder.onstop = () => {
          this.audioBlob = new Blob(audioChunks, {
            type: 'audio/wav'
          });
          stream.getTracks().forEach(track => track.stop());
        };
        this.mediaRecorder.start();
        this.isRecording = true;
        this.recordingTime = 0;
        this.recordingTimer = setInterval(() => {
          this.recordingTime++;
        }, 1000);
      } catch (error) {
        console.error('Error starting recording:', error);
        this.showError('Could not access microphone');
      }
    },
    stopRecording() {
      if (this.mediaRecorder && this.isRecording) {
        this.mediaRecorder.stop();
        this.isRecording = false;
        if (this.recordingTimer) {
          clearInterval(this.recordingTimer);
          this.recordingTimer = null;
        }
      }
    },
    playRecording() {
      if (this.audioBlob) {
        const audio = new Audio(URL.createObjectURL(this.audioBlob));
        audio.play();
      }
    },
    resetAudioState() {
      this.selectedAudioFile = null;
      this.audioBlob = null;
      this.recordingTime = 0;
      this.isDragOver = false;
    },
    // File handling methods
    triggerAudioFileInput() {
      this.$refs.audioFileInput.click();
    },
    handleAudioFileSelect(event) {
      const file = event.target.files[0];
      if (file) {
        this.selectedAudioFile = file;
      }
    },
    handleAudioDrop(event) {
      event.preventDefault();
      this.isDragOver = false;
      const files = event.dataTransfer.files;
      if (files.length > 0) {
        const file = files[0];
        if (file.type.startsWith('audio/')) {
          this.selectedAudioFile = file;
        } else {
          this.showError('Please select an audio file');
        }
      }
    },
    triggerDocumentFileInput() {
      this.$refs.documentFileInput.click();
    },
    handleDocumentFileSelect(event) {
      const file = event.target.files[0];
      if (file) {
        this.selectedDocumentFile = file;
      }
    },
    handleDocumentDrop(event) {
      event.preventDefault();
      this.isDragOverDoc = false;
      const files = event.dataTransfer.files;
      if (files.length > 0) {
        const file = files[0];
        const allowedTypes = ['.pdf', '.doc', '.docx', '.ppt', '.pptx'];
        const fileExtension = '.' + file.name.split('.').pop().toLowerCase();
        if (allowedTypes.includes(fileExtension)) {
          this.selectedDocumentFile = file;
        } else {
          this.showError('Please select a PDF, DOC, or PPT file');
        }
      }
    },
    // Processing methods
    async processAudio() {
      let audioFile = this.selectedAudioFile || this.audioBlob;
      if (!audioFile) {
        this.showError('Error', 'Please select or record an audio file');
        return;
      }

      // Convert blob to file if needed
      if (audioFile instanceof Blob && !(audioFile instanceof File)) {
        audioFile = new File([audioFile], 'recording.wav', {
          type: 'audio/wav'
        });
      }
      this.isProcessing = true;
      this.showProcessingModal = true;
      this.processingMessage = 'Processing audio and generating notes...';
      this.processingProgress = 20;
      this.closeAudioModal();
      try {
        // Process audio with AI
        const result = await processAudio(audioFile);
        this.processingProgress = 70;

        // Create note from AI result
        if (result.success && result.note) {
          const noteData = {
            title: result.note.title,
            content: result.note.content,
            category: 'Audio Notes',
            userId: this.userId
          };
          this.processingProgress = 90;
          await createNote(noteData);
          this.processingProgress = 100;
          this.showSuccess('Success', 'Audio processed successfully! Notes have been created.');
          await this.loadRecentNotes(); // Refresh notes
        } else {
          throw new Error(result.error || 'Failed to process audio');
        }
      } catch (error) {
        console.error('Audio processing error:', error);
        this.showError('Error', 'Failed to process audio. Please try again.');
      } finally {
        this.isProcessing = false;
        this.showProcessingModal = false;
        this.processingProgress = 0;
        this.selectedAudioFile = null;
        this.audioBlob = null;
      }
    },
    async processYouTube() {
      if (!this.youtubeUrl || !this.isValidYouTubeUrl(this.youtubeUrl)) {
        this.showError('Error', 'Please enter a valid YouTube URL');
        return;
      }
      this.isProcessing = true;
      this.showProcessingModal = true;
      this.processingMessage = 'Processing YouTube video and generating notes...';
      this.processingProgress = 20;
      this.closeYouTubeModal();
      try {
        // Process YouTube video with AI
        const result = await processYouTubeVideo(this.youtubeUrl);
        this.processingProgress = 70;

        // Create note from AI result
        if (result.success && result.note) {
          const noteData = {
            title: result.note.title,
            content: result.note.content,
            category: 'YouTube Notes',
            userId: this.userId
          };
          this.processingProgress = 90;
          await createNote(noteData);
          this.processingProgress = 100;
          this.showSuccess('Success', 'YouTube video processed successfully! Notes have been created.');
          await this.loadRecentNotes(); // Refresh notes
        } else {
          throw new Error(result.error || 'Failed to process YouTube video');
        }
      } catch (error) {
        console.error('YouTube processing error:', error);
        this.showError('Error', 'Failed to process YouTube video. Please try again.');
      } finally {
        this.isProcessing = false;
        this.showProcessingModal = false;
        this.processingProgress = 0;
        this.youtubeUrl = '';
      }
    },
    async processDocument() {
      if (!this.selectedDocumentFile) {
        this.showError('Error', 'Please select a document file');
        return;
      }
      this.isProcessing = true;
      this.showProcessingModal = true;
      this.processingMessage = 'Processing document and generating notes...';
      this.processingProgress = 20;
      this.closeDocumentModal();
      try {
        // Process document with AI
        const result = await processDocument(this.selectedDocumentFile);
        this.processingProgress = 70;

        // Create note from AI result
        if (result.success && result.note) {
          const noteData = {
            title: result.note.title,
            content: result.note.content,
            category: 'Document Notes',
            userId: this.userId
          };
          this.processingProgress = 90;
          await createNote(noteData);
          this.processingProgress = 100;
          this.showSuccess('Success', 'Document processed successfully! Notes have been created.');
          await this.loadRecentNotes(); // Refresh notes
        } else {
          throw new Error(result.error || 'Failed to process document');
        }
      } catch (error) {
        console.error('Document processing error:', error);
        this.showError('Error', 'Failed to process document. Please try again.');
      } finally {
        this.isProcessing = false;
        this.showProcessingModal = false;
        this.processingProgress = 0;
        this.selectedDocumentFile = null;
      }
    },
    async loadRecentNotes() {
      try {
        // Use local method instead of API import
        const userId = await getUserIdFromToken();
        if (!userId) {
          throw new Error('No valid user token found');
        }
        const notesResponse = await getUserNotes(userId);
        // Handle API response structure - extract data array
        const notesData = notesResponse.data || notesResponse || [];

        // Ensure notesData is an array before calling slice
        if (Array.isArray(notesData)) {
          this.recentNotes = notesData.slice(0, 5);
        } else {
          console.warn('Notes data is not an array:', notesData);
          this.recentNotes = [];
        }
      } catch (error) {
        console.error('Error loading notes:', error);
        this.recentNotes = []; // Ensure it's always an array
      }
    },
    // Utility methods
    isValidYouTubeUrl(url) {
      const youtubeRegex = /^(https?:\/\/)?(www\.)?(youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/;
      return youtubeRegex.test(url);
    },
    extractVideoTitle(url) {
      // Extract video ID and create a basic title
      const videoId = this.extractVideoId(url);
      return videoId ? `Video ${videoId}` : 'YouTube Video';
    },
    extractVideoId(url) {
      const match = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\n?#]+)/);
      return match ? match[1] : null;
    },
    getFileIcon(fileName) {
      const extension = fileName.split('.').pop().toLowerCase();
      const iconMap = {
        'pdf': 'fas fa-file-pdf',
        'doc': 'fas fa-file-word',
        'docx': 'fas fa-file-word',
        'ppt': 'fas fa-file-powerpoint',
        'pptx': 'fas fa-file-powerpoint'
      };
      return iconMap[extension] || 'fas fa-file';
    },
    formatFileSize(bytes) {
      if (bytes === 0) return '0 Bytes';
      const k = 1024;
      const sizes = ['Bytes', 'KB', 'MB', 'GB'];
      const i = Math.floor(Math.log(bytes) / Math.log(k));
      return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
    },
    // Note-related methods
    openNote(noteId) {
      this.$router.push(`/notes/${noteId}`);
    },
    async toggleNoteFavorite(note) {
      try {
        const {
          toggleNoteFavorite
        } = await import('../../api/Note.js');
        const updatedNote = await toggleNoteFavorite(note.id);
        note.isFavorite = updatedNote.isFavorite;
      } catch (error) {
        console.error('Error toggling note favorite:', error);
        note.isFavorite = !note.isFavorite;
      }
    },
    truncateNoteContent(content) {
      return content.length > 80 ? content.substring(0, 80) + '...' : content;
    },
    formatNoteDate(date) {
      return new Date(date).toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric'
      });
    }
  }
};
